parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "requiredKW": {
      "type": "number",
      "description": "Ideal solar capacity required to offset the user's current electricity consumption."
    },
    "maximumRoofKW": {
      "type": "number",
      "description": "Maximum solar capacity that can be installed on the available roof area."
    },
    "recommendedKW": {
      "type": "number",
      "description": "Final recommended solar system capacity after considering both electricity consumption and roof constraints."
    },
    "isRoofConstrained": {
      "type": "boolean",
      "description": "True if the roof area cannot accommodate the ideal required system size."
    },
    "consumptionCoverage": {
      "type": "number",
      "description": "Percentage of the user's electricity consumption that can be offset by the recommended system."
    },
    "panelCount": {
      "type": "integer",
      "description": "Estimated number of solar panels required."
    },
    "monthlyGeneration": {
      "type": "number",
      "description": "Estimated monthly electricity generation in kWh."
    },
    "monthlySavings": {
      "type": "number",
      "description": "Estimated monthly savings in Indian Rupees."
    },
    "systemCost": {
      "type": "number",
      "description": "Estimated total installation cost in Indian Rupees."
    },
    "paybackPeriod": {
      "type": "number",
      "description": "Estimated payback period in years."
    },
    "roofAreaUsed": {
      "type": "number",
      "description": "Estimated roof area required for the recommended solar installation in square feet."
    },
    "remainingRoofArea": {
      "type": "number",
      "description": "Unused roof area remaining after installation in square feet."
    },
    "recommendation": {
      "type": "string",
      "description": "AI-generated recommendation explaining the decision and any roof constraints."
    },
    "installers": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "name": {
            "type": "string"
          },
          "address": {
            "type": "string"
          },
          "phone": {
            "type": "string"
          },
          "website": {
            "type": "string"
          }
        },
        "required": [
          "name",
          "address",
          "website"
        ]
      }
    }
  },
  "required": [
    "requiredKW",
    "maximumRoofKW",
    "recommendedKW",
    "isRoofConstrained",
    "consumptionCoverage",
    "panelCount",
    "monthlyGeneration",
    "monthlySavings",
    "systemCost",
    "paybackPeriod",
    "roofAreaUsed",
    "remainingRoofArea",
    "recommendation",
    "installers"
  ]
}

